import React, { useEffect, useRef } from 'react';

interface InkCanvasProps {
  darkMode?: boolean;
}

const InkCanvas: React.FC<InkCanvasProps> = ({ darkMode = false }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const darkModeRef = useRef(darkMode);

  useEffect(() => {
    darkModeRef.current = darkMode;
  }, [darkMode]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    let width = window.innerWidth;
    let height = window.innerHeight;
    let animationFrameId: number;
    let frameCount = 0;

    // --- Shanshui Classes ---

    class MountainLayer {
      index: number;
      offset: number;
      speed: number;
      color: string;
      blur: number;
      amplitude: number;
      baseHeight: number;

      constructor(index: number, totalLayers: number) {
        this.index = index;
        // Scroll speed: Far mountains (low index) move slower than near ones
        this.speed = 0.1 + (index * 0.15); 
        this.offset = Math.random() * 1000;

        // Depth calculations (0 = Far/Back, 1 = Near/Front)
        const depth = index / (totalLayers - 1);

        // Color: Traditional "Blue-Green" Landscape (Qinglv) style fading to Ink
        // Far = Misty Blue/Grey, Near = Dark Ink
        if (depth < 0.3) {
            this.color = `rgba(140, 150, 160, ${0.3 + depth * 0.3})`; // Misty Blue
            this.blur = 4; // Blur distant mountains
        } else if (depth < 0.7) {
            this.color = `rgba(80, 90, 100, ${0.6 + depth * 0.2})`; // Stone Grey
            this.blur = 2;
        } else {
            this.color = `rgba(30, 30, 30, ${0.8 + depth * 0.2})`; // Deep Ink
            this.blur = 0;
        }

        this.amplitude = height * (0.1 + depth * 0.15);
        this.baseHeight = height * (0.6 + depth * 0.2); 
      }

      getY(x: number) {
        // Superposition of sine waves for organic mountain shape
        const scale = 0.002 + (this.index * 0.0005);
        const xOff = x + this.offset;

        let y = Math.sin(xOff * scale) * 1.0 +
                Math.sin(xOff * scale * 2.5) * 0.5 +
                Math.sin(xOff * scale * 5.0) * 0.2;

        // Noise texture for nearer mountains
        if (this.index > 1) {
             y += Math.sin(xOff * 0.02) * 0.05;
        }

        return this.baseHeight - Math.abs(y * this.amplitude);
      }

      draw(ctx: CanvasRenderingContext2D, scrollX: number, isNight: boolean) {
        // Adjust color for night mode
        let fillStyle = this.color;
        if (isNight) {
            const opacity = 0.1 + (this.index * 0.1);
            fillStyle = `rgba(200, 200, 210, ${opacity})`; // Inverted/Ghostly for "Secret" mode
        }

        ctx.fillStyle = fillStyle;
        if (!isNight && this.blur > 0) {
            ctx.filter = `blur(${this.blur}px)`;
        } else {
            ctx.filter = 'none';
        }

        ctx.beginPath();
        const step = 20; // Optimization
        ctx.moveTo(0, height);

        for (let x = 0; x <= width + step; x += step) {
            // Effectively scrolling the noise by adding scrollX
            const y = this.getY(x + scrollX * this.speed);
            ctx.lineTo(x, y);
        }

        ctx.lineTo(width, height);
        ctx.lineTo(0, height);
        ctx.fill();
        ctx.filter = 'none'; // Reset
      }
    }

    class Sun {
        draw(ctx: CanvasRenderingContext2D, isNight: boolean) {
            const x = width * 0.8;
            const y = height * 0.2;
            const r = height * 0.06;

            // In day: Red Seal Sun (Cinnabar). In Night: Pale Moon.
            ctx.beginPath();
            ctx.arc(x, y, r, 0, Math.PI * 2);

            if (isNight) {
                ctx.fillStyle = '#fdfbf7';
                ctx.shadowColor = '#ffffff';
                ctx.shadowBlur = 20;
            } else {
                ctx.fillStyle = '#b93a3a'; // Cinnabar
                ctx.shadowColor = 'rgba(185, 58, 58, 0.4)';
                ctx.shadowBlur = 0;
                ctx.globalAlpha = 0.85;
            }

            ctx.fill();
            ctx.shadowBlur = 0;
            ctx.globalAlpha = 1;
        }
    }

    class Boat {
        x: number;
        y: number;

        constructor() {
            this.x = width * 0.2;
            this.y = height * 0.85; // Float on the "water" (bottom area)
        }

        draw(ctx: CanvasRenderingContext2D, time: number, isNight: boolean) {
            // Bobbing animation
            const bob = Math.sin(time * 0.02) * 3;
            const y = this.y + bob;

            ctx.save();
            ctx.translate(this.x, y);

            // Scale boat based on screen
            const scale = 0.6;
            ctx.scale(scale, scale);

            ctx.fillStyle = isNight ? '#cccccc' : '#2b2b2b';

            // Hull
            ctx.beginPath();
            ctx.moveTo(-40, 0);
            ctx.quadraticCurveTo(0, 15, 40, 0);
            ctx.lineTo(35, -5);
            ctx.lineTo(-35, -5);
            ctx.fill();

            // Fisherman (simple silhouette)
            ctx.beginPath();
            ctx.arc(10, -12, 4, 0, Math.PI * 2); // Head
            ctx.fill();

            ctx.beginPath();
            ctx.moveTo(10, -8);
            ctx.lineTo(0, 0); // Body leaning
            ctx.stroke();

            // Pole
            ctx.strokeStyle = isNight ? '#cccccc' : '#2b2b2b';
            ctx.lineWidth = 1.5;
            ctx.beginPath();
            ctx.moveTo(5, -5);
            ctx.lineTo(60, 10);
            ctx.stroke();

            ctx.restore();
        }
    }

    // --- Init ---
    const layers: MountainLayer[] = [];
    const sun = new Sun();
    const boat = new Boat();

    const init = () => {
       layers.length = 0;
       const layerCount = 4;
       for (let i = 0; i < layerCount; i++) {
           layers.push(new MountainLayer(i, layerCount));
       }
    };

    const resize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      canvas.width = width;
      canvas.height = height;
      init();
    };

    let scrollX = 0;

    const animate = () => {
      const isNight = darkModeRef.current;
      frameCount++;
      scrollX += 0.5; // Constant scroll right (Landscape scroll unrolling)

      ctx.clearRect(0, 0, width, height);

      // 1. Draw Sky/Paper Tint
      if (!isNight) {
          // Subtle gradient for paper aging
          const grad = ctx.createLinearGradient(0, 0, 0, height);
          grad.addColorStop(0, 'rgba(230, 220, 200, 0.1)'); // Top slightly darker
          grad.addColorStop(1, 'rgba(255, 255, 255, 0)');
          ctx.fillStyle = grad;
          ctx.fillRect(0,0,width,height);
      }

      // 2. Sun/Moon (Behind mountains)
      sun.draw(ctx, isNight);

      // 3. Mountains
      layers.forEach(layer => layer.draw(ctx, scrollX, isNight));

      // 4. Boat (Foreground)
      boat.draw(ctx, frameCount, isNight);

      // 5. Mist/Texture Overlay
      // Add a static noise grain or fog at the bottom if needed, but keeping it clean for Shanshui style

      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', resize);
    resize();
    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className={`fixed inset-0 w-full h-full pointer-events-none z-0 transition-opacity duration-1000 ${darkMode ? 'opacity-90 mix-blend-screen' : 'opacity-100 mix-blend-multiply'}`}
    />
  );
};

export default InkCanvas;

