import React, { useEffect, useRef } from 'react';

interface InkCanvasProps {
  darkMode?: boolean;
}

const InkCanvas: React.FC<InkCanvasProps> = ({ darkMode = false }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let width = window.innerWidth;
    let height = window.innerHeight;
    let animationFrameId: number;
    let time = 0;

    // --- Configuration ---

    // --- Classes ---

    class Particle {
      x: number;
      y: number;
      vx: number;
      vy: number;
      life: number;
      maxLife: number;
      size: number;
      alpha: number;

      constructor(x: number, y: number) {
        this.init(x, y);
      }

      init(x: number, y: number) {
        this.x = x + (Math.random() - 0.5) * 20;
        this.y = y;
        this.vx = (Math.random() - 0.5) * 0.5;
        this.vy = 2 + Math.random() * 3;
        this.life = 0;
        this.maxLife = 100 + Math.random() * 50;
        this.size = 1 + Math.random() * 2;
        this.alpha = 0.5 + Math.random() * 0.5;
      }

      update() {
        this.x += this.vx;
        this.y += this.vy;
        this.life++;
        this.vy += 0.05; // Gravity

        // Interaction with "rocks" at bottom
        if (this.y > height * 0.85) {
             this.vy *= 0.5;
             this.vx += (Math.random() - 0.5) * 2;
             this.alpha -= 0.02;
        }
      }

      draw(ctx: CanvasRenderingContext2D) {
        ctx.fillStyle = `rgba(250, 250, 250, ${this.alpha * 0.6})`;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    class Mist {
        x: number;
        y: number;
        r: number;
        vx: number;

        constructor() {
            this.init();
        }

        init() {
            this.x = (width * 0.2) + Math.random() * (width * 0.3);
            this.y = height * 0.85 + Math.random() * 100;
            this.r = 30 + Math.random() * 50;
            this.vx = (Math.random() - 0.5) * 0.2;
        }

        update() {
            this.x += this.vx;
            this.y -= 0.2;
            this.r += 0.1;
            if (this.y < height * 0.6) this.init();
        }

        draw(ctx: CanvasRenderingContext2D) {
            const grad = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.r);
            grad.addColorStop(0, 'rgba(255, 255, 255, 0.2)');
            grad.addColorStop(1, 'rgba(255, 255, 255, 0)');
            ctx.fillStyle = grad;
            ctx.beginPath();
            ctx.arc(this.x, this.y, this.r, 0, Math.PI * 2);
            ctx.fill();
        }
    }

    // Static drawing functions
    const drawCliff = () => {
        // Draw offscreen or just redraw? For static background, redraw is expensive every frame?
        // Let's cache the static parts.
    };

    // Prepare offscreen canvas for static elements (Mountains, Trees)
    const staticCanvas = document.createElement('canvas');
    const staticCtx = staticCanvas.getContext('2d');

    const generateStaticScene = () => {
        if (!staticCtx) return;
        staticCanvas.width = width;
        staticCanvas.height = height;

        // 1. Draw Cliffs (Left Side)
        staticCtx.fillStyle = '#1a1a1a'; // Ink color

        // Gradient for depth
        const grad = staticCtx.createLinearGradient(0, 0, width * 0.5, 0);
        grad.addColorStop(0, 'rgba(30,30,30,0.9)');
        grad.addColorStop(0.6, 'rgba(50,50,50,0.7)');
        grad.addColorStop(1, 'rgba(255,255,255,0)'); // Fade to void

        staticCtx.fillStyle = grad;

        staticCtx.beginPath();
        staticCtx.moveTo(0, 0);

        // Top edge
        let x = 0;
        let y = 0;

        // Jagged cliff face down
        const cliffEdgeX = width * 0.25;

        staticCtx.lineTo(cliffEdgeX, 0);

        // Downward jagged line
        for (let yi = 0; yi < height; yi += 20) {
            const noise = (Math.random() - 0.5) * 30;
            const xOffset = Math.sin(yi * 0.01) * 50;

            // Indent for waterfall start
            let indent = 0;
            if (yi > height * 0.15 && yi < height * 0.2) {
                 indent = -20; // Slight lip
            }

            staticCtx.lineTo(cliffEdgeX + xOffset + noise + indent, yi);
        }

        staticCtx.lineTo(0, height);
        staticCtx.closePath();
        staticCtx.fill();

        // 2. Draw Pine Tree (Bottom Left)
        const treeX = width * 0.15;
        const treeY = height * 0.75;

        drawPine(staticCtx, treeX, treeY, 80, -Math.PI / 2);

        // 3. Draw a Scholar/Figure (Tiny)
        drawScholar(staticCtx, width * 0.28, height * 0.85);
    };

    const drawPine = (ctx: CanvasRenderingContext2D, x: number, y: number, len: number, angle: number, depth = 0) => {
        if (depth > 4) return;

        const endX = x + Math.cos(angle) * len;
        const endY = y + Math.sin(angle) * len;

        ctx.strokeStyle = `rgba(20,20,20, ${0.8 + depth * 0.05})`;
        ctx.lineWidth = Math.max(1, (5 - depth) * 2);
        ctx.lineCap = 'round';

        ctx.beginPath();
        ctx.moveTo(x, y);
        // Curve branch
        const ctrlX = (x + endX) / 2 + (Math.random() - 0.5) * len * 0.5;
        const ctrlY = (y + endY) / 2 + (Math.random() - 0.5) * len * 0.5;
        ctx.quadraticCurveTo(ctrlX, ctrlY, endX, endY);
        ctx.stroke();

        // Needles at ends
        if (depth > 2) {
            ctx.fillStyle = 'rgba(10,30,20,0.6)'; // Dark green/ink
            for(let i=0; i<5; i++) {
                ctx.beginPath();
                ctx.arc(endX + (Math.random()-0.5)*20, endY + (Math.random()-0.5)*15, 3 + Math.random()*4, 0, Math.PI*2);
                ctx.fill();
            }
        }

        const branches = 2;
        for (let i = 0; i < branches; i++) {
            const newLen = len * (0.6 + Math.random() * 0.2);
            const newAngle = angle + (Math.random() - 0.5) * 1.5;
            drawPine(ctx, endX, endY, newLen, newAngle, depth + 1);
        }
    };

    const drawScholar = (ctx: CanvasRenderingContext2D, x: number, y: number) => {
        // Simple silhouette
        ctx.fillStyle = '#000';
        ctx.beginPath();
        // Body
        ctx.moveTo(x, y);
        ctx.lineTo(x - 5, y + 15);
        ctx.lineTo(x + 5, y + 15);
        ctx.fill();
        // Head
        ctx.beginPath();
        ctx.arc(x, y - 3, 3, 0, Math.PI * 2);
        ctx.fill();
        // Hat
        ctx.beginPath();
        ctx.moveTo(x - 6, y - 5);
        ctx.lineTo(x + 6, y - 5);
        ctx.stroke();
    };

    // --- State ---
    const particles: Particle[] = [];
    const mists: Mist[] = [];

    const init = () => {
       generateStaticScene();
       particles.length = 0;
       mists.length = 0;

       for(let i=0; i<10; i++) mists.push(new Mist());
    };

    const resize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      const dpr = window.devicePixelRatio || 1;
      canvas.width = width * dpr;
      canvas.height = height * dpr;
      ctx.scale(dpr, dpr);
      init();
    };

    const animate = () => {
      ctx.clearRect(0, 0, width, height);

      // Draw Static Layer
      if (staticCanvas.width > 0) {
        ctx.drawImage(staticCanvas, 0, 0, width, height);
      }

      // Waterfall Source
      const waterfallX = width * 0.25;
      const waterfallY = height * 0.15;

      // Spawn water particles
      for(let i=0; i<5; i++) {
          particles.push(new Particle(waterfallX + (Math.random()-0.5)*30, waterfallY));
      }

      // Update and Draw Particles (Waterfall)
      for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        p.update();
        p.draw(ctx);
        if (p.life > p.maxLife || p.y > height) {
          particles.splice(i, 1);
        }
      }

      // Mist at bottom
      mists.forEach(m => {
          m.update();
          m.draw(ctx);
      });

      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', resize);
    resize();
    animate();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className="fixed inset-0 w-full h-full pointer-events-none z-0 transition-opacity duration-1000 opacity-90"
      style={{ mixBlendMode: 'normal' }}
    />
  );
};

