import React, { useEffect, useRef } from 'react';

interface InkCanvasProps {
  darkMode?: boolean;
}

const InkCanvas: React.FC<InkCanvasProps> = ({ darkMode = false }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let width = window.innerWidth;
    let height = window.innerHeight;
    let animationFrameId: number;

    // Offscreen canvas for static elements (Mountains, Trees, Rocks) to improve performance
    const staticCanvas = document.createElement('canvas');
    const staticCtx = staticCanvas.getContext('2d');

    // --- Classes & Helpers ---

    class WaterParticle {
      x: number;
      y: number;
      vx: number;
      vy: number;
      life: number;
      size: number;

      constructor(x: number, y: number) {
        this.reset(x, y);
      }

      reset(x: number, y: number) {
        this.x = x + (Math.random() - 0.5) * 15; // Spread at source
        this.y = y;
        this.vx = (Math.random() - 0.5) * 0.5;
        this.vy = 2 + Math.random() * 3; // Initial fall speed
        this.life = 1.0;
        this.size = 1 + Math.random() * 1.5;
      }

      update(height: number, cliffBottom: number) {
        this.x += this.vx;
        this.y += this.vy;
        this.vy += 0.1; // Gravity
        this.life -= 0.005;

        // Interaction with bottom (mist/splash)
        if (this.y > cliffBottom - 50) {
            this.life -= 0.02; // Fade out faster at bottom
            this.vx += (Math.random() - 0.5) * 2; // Scatter
        }
      }

      draw(ctx: CanvasRenderingContext2D) {
        ctx.fillStyle = `rgba(255, 255, 255, ${this.life * 0.6})`;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    class MistParticle {
        x: number;
        y: number;
        r: number;
        vx: number;

        constructor() {
            this.init();
        }

        init() {
            this.x = Math.random() * width;
            this.y = height - Math.random() * (height * 0.3);
            this.r = 40 + Math.random() * 80;
            this.vx = 0.2 + Math.random() * 0.3;
        }

        update() {
            this.x += this.vx;
            if (this.x - this.r > width) {
                this.x = -this.r;
            }
        }

        draw(ctx: CanvasRenderingContext2D) {
            const grad = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.r);
            grad.addColorStop(0, 'rgba(255, 255, 255, 0.8)');
            grad.addColorStop(1, 'rgba(255, 255, 255, 0)');
            ctx.fillStyle = grad;
            ctx.beginPath();
            ctx.arc(this.x, this.y, this.r, 0, Math.PI * 2);
            ctx.fill();
        }
    }

    // --- Drawing Functions ---

    const drawPine = (ctx: CanvasRenderingContext2D, x: number, y: number, len: number, angle: number, depth: number) => {
        if (depth === 0) return;

        const endX = x + Math.cos(angle) * len;
        const endY = y + Math.sin(angle) * len;

        // Draw Branch
        ctx.beginPath();
        ctx.moveTo(x, y);

        // Slight curve for natural look
        const midX = (x + endX) / 2 + (Math.random() - 0.5) * len * 0.2;
        const midY = (y + endY) / 2 + (Math.random() - 0.5) * len * 0.2;

        ctx.quadraticCurveTo(midX, midY, endX, endY);

        ctx.lineWidth = Math.max(1, depth * 1.5);
        ctx.strokeStyle = `rgba(20, 20, 20, ${0.7 + Math.random()*0.3})`;
        ctx.lineCap = 'round';
        ctx.stroke();

        // Draw Needles at tips
        if (depth <= 3) {
            ctx.beginPath();
            ctx.fillStyle = 'rgba(30, 40, 35, 0.7)';
            // Draw a cluster of needles
            for (let i = 0; i < 5; i++) {
                 const nx = endX + (Math.random() - 0.5) * 25;
                 const ny = endY + (Math.random() - 0.5) * 15;
                 ctx.moveTo(endX, endY);
                 ctx.lineTo(nx, ny);
            }
            ctx.lineWidth = 0.5;
            ctx.stroke();
        }

        // Recursion
        const branches = 2;
        for (let i = 0; i < branches; i++) {
            const newLen = len * (0.6 + Math.random() * 0.2);
            const newAngle = angle + (Math.random() - 0.5) * 1.0;
            drawPine(ctx, endX, endY, newLen, newAngle, depth - 1);
        }
    };

    const drawScholar = (ctx: CanvasRenderingContext2D, x: number, y: number) => {
        const scale = 0.8;
        ctx.save();
        ctx.translate(x, y);
        ctx.scale(scale, scale);

        ctx.fillStyle = '#111';

        // Body (Robe)
        ctx.beginPath();
        ctx.moveTo(0, 0);
        ctx.lineTo(-6, 25); // Left side
        ctx.lineTo(8, 25);  // Right side
        ctx.lineTo(4, 5);   // Shoulder
        ctx.fill();

        // Head
        ctx.beginPath();
        ctx.arc(0, -5, 4, 0, Math.PI * 2);
        ctx.fill();

        // Straw Hat (Conical)
        ctx.beginPath();
        ctx.moveTo(-10, -5);
        ctx.lineTo(10, -5);
        ctx.lineTo(0, -12);
        ctx.closePath();
        ctx.lineWidth = 1;
        ctx.strokeStyle = '#111';
        ctx.stroke();
        ctx.fill();

        ctx.restore();
    };

    const generateScene = () => {
        if (!staticCtx) return;
        staticCanvas.width = width;
        staticCanvas.height = height;

        const cliffWidth = Math.min(width * 0.35, 400); // Cliff takes left side
        const cliffHeight = height * 0.85;

        // 1. Draw Main Cliff Body (Left)
        // Gradient for volume
        const grad = staticCtx.createLinearGradient(0, 0, cliffWidth, 0);
        grad.addColorStop(0, 'rgba(20, 20, 20, 0.9)');
        grad.addColorStop(0.4, 'rgba(40, 40, 40, 0.8)');
        grad.addColorStop(0.8, 'rgba(80, 80, 80, 0.4)');
        grad.addColorStop(1, 'rgba(255, 255, 255, 0)'); // Fade into mist

        staticCtx.fillStyle = grad;
        staticCtx.beginPath();
        staticCtx.moveTo(0, 0);

        // Jagged Edge down
        let cy = 0;
        let cx = cliffWidth;
        const waterfallSlotStart = height * 0.1;

        while (cy < height) {
            cy += 10 + Math.random() * 20;
            // Create indentation for waterfall
            let indent = 0;
            // The waterfall cut
            if (cy > waterfallSlotStart && cy < height * 0.7) {
                 indent = -50 - Math.random() * 20;
            }

            const noise = (Math.random() - 0.5) * 30;
            staticCtx.lineTo(cx + indent + noise, cy);
        }

        staticCtx.lineTo(0, height);
        staticCtx.closePath();
        staticCtx.fill();

        // 2. Add darker "Ink strokes" on the cliff for texture
        staticCtx.strokeStyle = 'rgba(10, 10, 10, 0.3)';
        staticCtx.lineWidth = 2;
        for(let i=0; i<30; i++) {
            const sx = Math.random() * cliffWidth * 0.6;
            const sy = Math.random() * height * 0.8;
            staticCtx.beginPath();
            staticCtx.moveTo(sx, sy);
            staticCtx.lineTo(sx + 20, sy + 40 + Math.random() * 40);
            staticCtx.stroke();
        }

        // 3. Tree on Cliff Top
        drawPine(staticCtx, cliffWidth * 0.4, height * 0.05, 50, Math.PI/2, 5);

        // 4. Tree clinging to Cliff Side
        drawPine(staticCtx, cliffWidth * 0.8, height * 0.4, 40, 0, 4);

        // 5. Bottom Left Rock & Main Tree (Foreground)
        const rockX = width * 0.15;
        const rockY = height * 0.85;

        // Rock shape
        staticCtx.fillStyle = 'rgba(30,30,30,0.8)';
        staticCtx.beginPath();
        staticCtx.arc(rockX, rockY + 50, 80, Math.PI, 0);
        staticCtx.fill();

        // Main Pine Tree
        drawPine(staticCtx, rockX, rockY, 70, -Math.PI / 2, 6);

        // 6. Scholar Rock (Bottom Center-Right)
        const scholarRockX = width * 0.55;
        const scholarRockY = height * 0.92;

        // Rock
        staticCtx.fillStyle = 'rgba(40,40,45,0.7)';
        staticCtx.beginPath();
        staticCtx.ellipse(scholarRockX, scholarRockY + 20, 60, 40, 0, 0, Math.PI * 2);
        staticCtx.fill();

        // Scholar
        drawScholar(staticCtx, scholarRockX, scholarRockY - 20);
    };

    // --- State & Loop ---
    const particles: WaterParticle[] = [];
    const mistParticles: MistParticle[] = [];

    const init = () => {
        generateScene();
        particles.length = 0;
        mistParticles.length = 0;

        for(let i=0; i<15; i++) mistParticles.push(new MistParticle());
    };

    const animate = () => {
        ctx.clearRect(0, 0, width, height);

        // 1. Draw Static Layer
        if (staticCanvas.width > 0) {
            ctx.drawImage(staticCanvas, 0, 0);
        }

        // 2. Draw Waterfall
        // Source position roughly based on cliff generation logic
        const waterfallX = Math.min(width * 0.35, 400) - 30; 
        const waterfallY = height * 0.12;

        // Spawn particles
        for(let i=0; i<3; i++) {
            particles.push(new WaterParticle(waterfallX, waterfallY));
        }

        // Update & Draw Water
        for (let i = particles.length - 1; i >= 0; i--) {
            const p = particles[i];
            p.update(height, height * 0.85);
            p.draw(ctx);
            if (p.life <= 0 || p.y > height) {
                particles.splice(i, 1);
            }
        }

        // 3. Draw Mist (Foreground) to create depth
        mistParticles.forEach(m => {
            m.update();
            m.draw(ctx);
        });

        // 4. White wash at bottom of waterfall
        const grad = ctx.createRadialGradient(waterfallX, height * 0.8, 0, waterfallX, height * 0.8, 100);
        grad.addColorStop(0, 'rgba(255,255,255,0.4)');
        grad.addColorStop(1, 'rgba(255,255,255,0)');
        ctx.fillStyle = grad;
        ctx.fillRect(waterfallX - 100, height * 0.7, 200, 200);

        animationFrameId = requestAnimationFrame(animate);
    };

    const handleResize = () => {
        width = window.innerWidth;
        height = window.innerHeight;
        const dpr = window.devicePixelRatio || 1;
        canvas.width = width * dpr;
        canvas.height = height * dpr;
        ctx.scale(dpr, dpr);
        init();
    };

    window.addEventListener('resize', handleResize);
    handleResize();
    animate();

    return () => {
        window.removeEventListener('resize', handleResize);
        cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      className={`fixed inset-0 w-full h-full pointer-events-none z-0 transition-opacity duration-1000 ${darkMode ? 'opacity-30 invert' : 'opacity-100'}`}
      style={{ mixBlendMode: 'multiply' }}
    />
  );
};

